+        "minimal" | "min" => Some(ThinkingLevel::Minimal),
+        "low" | "1" => Some(ThinkingLevel::Low),
+        "medium" | "med" | "2" => Some(ThinkingLevel::Medium),
+        "high" | "3" => Some(ThinkingLevel::High),
+        "xhigh" | "4" => Some(ThinkingLevel::XHigh),
+        _ => None,
+    }
+}
